package main

import (
    "archive/tar"
    "archive/zip"
    "errors"
    "fmt"
    "io"
    "os"
    "path/filepath"
    "strings"
)

// Compliant: Secure zip extraction with path validation
func extractZipSecure(src, dest string) error {
    reader, err := zip.OpenReader(src)
    if err != nil {
        return err
    }
    defer reader.Close()

    // Ensure destination directory exists
    os.MkdirAll(dest, 0755)

    for _, file := range reader.File {
        path, err := sanitizeExtractPath(dest, file.Name)
        if err != nil {
            return fmt.Errorf("invalid file path %s: %v", file.Name, err)
        }

        if file.FileInfo().IsDir() {
            err := os.MkdirAll(path, file.FileInfo().Mode())
            if err != nil {
                return err
            }
            continue
        }

        err = extractFile(file, path)
        if err != nil {
            return fmt.Errorf("failed to extract %s: %v", file.Name, err)
        }
    }
    return nil
}

// Sanitize and validate extraction path
func sanitizeExtractPath(dest, filename string) (string, error) {
    // Clean the filename path
    cleanName := filepath.Clean(filename)

    // Check for directory traversal patterns
    if strings.Contains(cleanName, "..") {
        return "", errors.New("path contains directory traversal")
    }

    // Check for absolute paths
    if filepath.IsAbs(cleanName) {
        return "", errors.New("path is absolute")
    }

    // Build the destination path
    destPath := filepath.Join(dest, cleanName)

    // Ensure the path is still within the destination directory
    destPath = filepath.Clean(destPath)
    if !strings.HasPrefix(destPath, filepath.Clean(dest)+string(os.PathSeparator)) {
        return "", errors.New("path escapes destination directory")
    }

    return destPath, nil
}

func extractFile(file *zip.File, destPath string) error {
    // Create directory structure
    err := os.MkdirAll(filepath.Dir(destPath), 0755)
    if err != nil {
        return err
    }

    // Open file from archive
    rc, err := file.Open()
    if err != nil {
        return err
    }
    defer rc.Close()

    // Create destination file
    outFile, err := os.OpenFile(destPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, file.FileInfo().Mode())
    if err != nil {
        return err
    }
    defer outFile.Close()

    // Limit file size to prevent zip bombs
    limitedReader := io.LimitReader(rc, 100*1024*1024) // 100MB limit

    _, err = io.Copy(outFile, limitedReader)
    return err
}

// Compliant: Secure tar extraction
func extractTarSecure(src, dest string) error {
    file, err := os.Open(src)
    if err != nil {
        return err
    }
    defer file.Close()

    tarReader := tar.NewReader(file)

    for {
        header, err := tarReader.Next()
        if err == io.EOF {
            break
        }
        if err != nil {
            return err
        }

        // Validate and sanitize path
        path, err := sanitizeExtractPath(dest, header.Name)
        if err != nil {
            return fmt.Errorf("invalid path %s: %v", header.Name, err)
        }

        switch header.Typeflag {
        case tar.TypeDir:
            err = os.MkdirAll(path, 0755)
            if err != nil {
                return err
            }
        case tar.TypeReg:
            err = extractTarFile(tarReader, path, header)
            if err != nil {
                return err
            }
        case tar.TypeSymlink, tar.TypeLink:
            // Handle links securely or skip them
            return errors.New("symbolic and hard links are not supported for security")
        }
    }
    return nil
}

func extractTarFile(tarReader *tar.Reader, destPath string, header *tar.Header) error {
    // Create directory structure
    err := os.MkdirAll(filepath.Dir(destPath), 0755)
    if err != nil {
        return err
    }

    // Create destination file
    outFile, err := os.Create(destPath)
    if err != nil {
        return err
    }
    defer outFile.Close()

    // Limit file size
    limitedReader := io.LimitReader(tarReader, header.Size)
    if header.Size > 100*1024*1024 { // 100MB limit
        return errors.New("file too large")
    }

    _, err = io.Copy(outFile, limitedReader)
    return err
}

// Compliant: Archive extraction with additional security measures
type SecureExtractor struct {
    MaxFileSize   int64
    MaxFiles      int
    AllowedExts   map[string]bool
    DestinationDir string
}

func NewSecureExtractor(destDir string) *SecureExtractor {
    return &SecureExtractor{
        MaxFileSize:   100 * 1024 * 1024, // 100MB
        MaxFiles:      1000,
        AllowedExts:   map[string]bool{".txt": true, ".json": true, ".csv": true},
        DestinationDir: destDir,
    }
}

func (se *SecureExtractor) ExtractZip(src string) error {
    reader, err := zip.OpenReader(src)
    if err != nil {
        return err
    }
    defer reader.Close()

    if len(reader.File) > se.MaxFiles {
        return fmt.Errorf("too many files in archive (max %d)", se.MaxFiles)
    }

    for _, file := range reader.File {
        if err := se.validateAndExtractFile(file); err != nil {
            return err
        }
    }

    return nil
}

func (se *SecureExtractor) validateAndExtractFile(file *zip.File) error {
    // Check file size
    if file.UncompressedSize64 > uint64(se.MaxFileSize) {
        return fmt.Errorf("file %s exceeds size limit", file.Name)
    }

    // Check file extension
    ext := filepath.Ext(file.Name)
    if !se.AllowedExts[ext] {
        return fmt.Errorf("file extension %s not allowed", ext)
    }

    // Sanitize path
    path, err := sanitizeExtractPath(se.DestinationDir, file.Name)
    if err != nil {
        return err
    }

    // Extract file
    return extractFile(file, path)
}
